from itertools import product
for length in range(1, 10):
    for cmds in product([1,2], repeat=length):
        x = 1
        for c in cmds:
            if c == 1: x += 2
            else: x *= 3
        if x == 9:
            print(length)
            exit()

from itertools import product
for start in range(1, 100):
    for cmds in product([1,2], repeat=2):
        x = start
        for c in cmds:
            if c == 1: x += 2
            else: x *= 2
        if x >= 20:
            print(start)
            exit()

from itertools import product
count = 0
for cmds in product([1,2], repeat=3):
    x = 2
    for c in cmds:
        if c == 1: x += 1
        else: x *= 2
    if x == 8:
        count += 1
print(count)

from itertools import product
count = 0
for cmds in product([1,2], repeat=5):
    x = 1
    for c in cmds:
        if c == 1: x += 1
        else: x *= 2
    if x % 2 == 0:
        count += 1
print(count)
